//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Run toggle properties (bold, italic, caps, strike, effects) and XOR
//! resolution".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from ECMA-376 /
//! ISO/IEC 29500 / MS-OI29500. A FAILING assertion means stemma DIVERGES from
//! Word: that is a real Word-compliance gap, NOT something to make pass by
//! weakening the test. The assertion messages carry the rule text + §refs so a
//! failure is self-explanatory.
//!
//! Methodology — consumption vs. save:
//!   stemma round-trips UNTOUCHED content byte-verbatim. So `reserialize()` of an
//!   unedited document reflects stemma's verbatim-preservation contract, not
//!   Word's render-time normalization. `xml*` assertions here are therefore used
//!   ONLY for child/element ORDERING (Annex A / CT_RPrBase sequence) — markup the
//!   serializer actively rebuilds via `build_rpr()`. Word CONSUMPTION semantics
//!   (display-only toggles never change stored characters) are tested on the READ
//!   side via `read_accepted()` / `read_rejected()`.

use std::io::Read;

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-docx plumbing ─────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` are additional
/// package parts as `(part_path, xml)` (e.g. `("word/styles.xml", "…")`); a
/// content-type Override is emitted for each based on its file name.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let part_path = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        let content_type = if part_path.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if part_path.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_path}" ContentType="{content_type}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            let part = part.trim_start_matches('/').to_string();
            zip.start_file(part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip for document.xml");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in docx");
    let mut out = String::new();
    file.read_to_string(&mut out)
        .expect("read word/document.xml");
    out
}

/// Parse → serialize(default) → return the serialized `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let serialized = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&serialized)
}

/// Returns true iff each needle appears in `haystack` in the given order
/// (translation of an `xmlRegex` `a [\s\S]*? b [\s\S]*? c` ordering check into a
/// dependency-free sequential `find`; no `regex` dev-dependency is available).
fn contains_in_order(haystack: &str, needles: &[&str]) -> bool {
    let mut cursor = 0usize;
    for needle in needles {
        match haystack[cursor..].find(needle) {
            Some(rel) => cursor += rel + needle.len(),
            None => return false,
        }
    }
    true
}

fn assert_opens_clean(bytes: &[u8], rule_ref: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule_ref} — expected document to open clean (no validation issues), got: {:?}",
        report.issues
    );
}

fn accepted_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for accept")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn rejected_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for reject")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

