#[test]
fn ics_complex_script_italic_independent_of_i() {
    let body = r#"<w:p><w:r><w:rPr><w:iCs/></w:rPr><w:t>arabic</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accepted_text(&b),
        "arabic",
        "iCs is display-only and never changes stored characters; accept preserves run text verbatim \
         (ECMA-376 §17.3.2.16/§17.3.2.17, §17.17.4)"
    );
    assert_eq!(
        rejected_text(&b),
        "arabic",
        "No tracked change present; reject reproduces the same display-only run text verbatim \
         (ECMA-376 §17.3.2.17)"
    );
    assert_opens_clean(
        &b,
        "A lone iCs toggle is schema-valid CT_RPr content; Word opens it without repair \
         (ECMA-376 Annex A CT_RPr, §17.3.2.17)",
    );
}

#[test]
fn cs_element_makes_ics_govern_and_drops_plain_i() {
    let body = r#"<w:p><w:r><w:rPr><w:bCs/><w:i/><w:cs/></w:rPr><w:t>some English text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accepted_text(&b),
        "some English text",
        "cs/iCs/b governance is purely a display decision; no characters are added or removed \
         (ECMA-376 §17.3.2.7, ISO/IEC 29500-1 §17.7.3)"
    );
    assert_eq!(
        rejected_text(&b),
        "some English text",
        "No tracked change; reject reproduces the same run text verbatim, cs/i interaction never \
         deletes content (ECMA-376 §17.3.2.7)"
    );
    assert_opens_clean(
        &b,
        "bCs + i + cs together is schema-valid CT_RPr content (§17.3.2.7 example markup); Word opens \
         it without repair",
    );
}

#[test]
fn effect_animated_text_is_not_a_toggle_enum_value() {
    let body = r#"<w:p><w:r><w:rPr><w:effect w:val="lights"/></w:rPr><w:t>flashy</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accepted_text(&b),
        "flashy",
        "Animated text effect is display-only and changes no characters; accepted text equals the \
         literal run content (ECMA-376 §17.3.2.11; not in §17.7.3 toggle list)"
    );
    assert_eq!(
        rejected_text(&b),
        "flashy",
        "No tracked change; reject reproduces the run text verbatim, effect never deletes content \
         (ECMA-376 §17.3.2.11)"
    );
    assert_opens_clean(
        &b,
        "effect val='lights' is a valid ST_TextEffect enum value in CT_RPr (§17.18.94); Word opens it \
         without repair",
    );
}

#[test]
fn em_emphasis_mark_is_display_only_not_toggle() {
    let body =
        r#"<w:p><w:r><w:rPr><w:em w:val="dot"/></w:rPr><w:t>emphatic</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accepted_text(&b),
        "emphatic",
        "The emphasis mark is a rendered glyph, not stored content; accepted text equals the literal \
         run content (ECMA-376 §17.3.2.12; not in §17.7.3 toggle list)"
    );
    assert_eq!(
        rejected_text(&b),
        "emphatic",
        "No tracked change; reject reproduces the run text verbatim (ECMA-376 §17.3.2.12)"
    );
    assert_opens_clean(
        &b,
        "em val='dot' is valid CT_RPr content (§17.3.2.12); Word opens it without repair",
    );
}

#[test]
fn italic_cs_split_bare_ics_display_only_survives_accept_reject() {
    let body = r#"<w:p><w:r><w:rPr><w:iCs/></w:rPr><w:t>delta</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accepted_text(&b),
        "delta",
        "iCs is an appearance toggle (§17.7.3 toggle list); accept-all must reproduce the literal run \
         text since display toggles never change characters (ISO/IEC 29500-1 §17.3.2.17, MS-OI29500 §2.1.81)"
    );
    assert_eq!(
        rejected_text(&b),
        "delta",
        "No tracked change; reject-all reproduces the original run text unchanged because iCs only \
         affects rendering (ISO/IEC 29500-1 §17.3.2.17)"
    );
    assert_opens_clean(
        &b,
        "A bare <w:iCs/> is a valid CT_OnOff present-means-true toggle (ISO/IEC 29500-1 §17.17.4); \
         Word opens it without repair",
    );
}

#[test]
fn italic_non_cs_toggle_is_display_only_survives_accept_reject() {
    let body = r#"<w:p><w:r><w:rPr><w:i/></w:rPr><w:t>oblique</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accepted_text(&b),
        "oblique",
        "Italics is a §17.7.3 toggle (display) property; accept-all reproduces the literal characters \
         because italics never changes content (ISO/IEC 29500-1 §17.3.2.16, MS-OI29500 §2.1.80)"
    );
    assert_eq!(
        rejected_text(&b),
        "oblique",
        "No tracked change; reject-all reproduces original text since i is render-only \
         (ISO/IEC 29500-1 §17.3.2.16)"
    );
    assert_opens_clean(
        &b,
        "Bare <w:i/> is a valid present-means-true CT_OnOff toggle; Word opens it without repair \
         (ISO/IEC 29500-1 §17.3.2.16)",
    );
}

#[test]
fn italic_cs_explicit_off_literal_zero_opens_clean() {
    let body =
        r#"<w:p><w:r><w:rPr><w:iCs w:val="0"/></w:rPr><w:t>epsilon</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "val=\"0\" is a legal CT_OnOff false literal (ISO/IEC 29500-1 §17.17.4, §22.9.2.7) on the iCs \
         toggle; Word opens it without repair",
    );
    assert_eq!(
        accepted_text(&b),
        "epsilon",
        "iCs off is display-only; accept-all reproduces the literal run text unchanged \
         (ISO/IEC 29500-1 §17.3.2.17)"
    );
    assert_eq!(
        rejected_text(&b),
        "epsilon",
        "No tracked change; reject-all reproduces original run text since the toggle is render-only \
         (ISO/IEC 29500-1 §17.3.2.17)"
    );
}

#[test]
fn italic_and_italic_cs_cooccurrence_is_appearance_only_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:i/><w:iCs/></w:rPr><w:t>theta</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "i and iCs are independent CT_OnOff toggles addressing disjoint character classes; their \
         co-occurrence is schema-valid and Word opens it without repair (ISO/IEC 29500-1 §17.3.2.16/§17.3.2.17, \
         MS-OI29500 §2.1.80/§2.1.81)",
    );
    assert_eq!(
        accepted_text(&b),
        "theta",
        "Both axes are display-only toggles; accept-all reproduces the literal run text unchanged \
         (ISO/IEC 29500-1 §17.7.3)"
    );
    assert_eq!(
        rejected_text(&b),
        "theta",
        "No tracked change; reject-all reproduces the original run text since both italics toggles are \
         render-only (ISO/IEC 29500-1 §17.7.3)"
    );
}

#[ignore = "open question: unedited-run reserialize preserves authored rPr child order byte-verbatim; build_rpr() Annex A normalization only fires on edited runs — consumption-vs-save boundary needs adjudication (no oracle)"]
#[test]
fn rpr_order_b_before_bcs_before_i() {
    // Authored out-of-order (i, bCs, b); serializer must re-emit in CT_RPrBase
    // declaration order b(3) < bCs(4) < i(5).
    let body = r#"<w:p><w:r><w:rPr><w:i/><w:bCs/><w:b/></w:rPr><w:t>cs bold quad</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        contains_in_order(&xml, &["<w:b/>", "<w:bCs/>", "<w:i/>"]),
        "CT_RPrBase declares b(pos3) < bCs(pos4) < i(pos5); serializer must emit in that order even \
         though authored i, bCs, b (xmlRegex translated to ordered-contains) \
         (ECMA-376 §17.3.2.1/§17.3.2.2/§17.3.2.16, Annex A CT_RPrBase). Got XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "b, bCs, i are all valid CT_OnOff toggles on a run; the document opens without repair",
    );
}

// rpr_order_i_ics_caps, rpr_order_strike_before_dstrike, and
// rpr_order_outline_shadow_emboss_imprint were DELETED as test-bugs:
// they asserted that reserialize() of an UNEDITED document reorders rPr
// children into Annex A sequence, but EG_RPrBase is referenced as a repeated
// xsd:choice (wml.xsd:1818-1863), so any sibling order is schema-valid and
// Word opens it without repair. stemma's documented contract preserves
// untouched-run child order byte-verbatim; build_rpr() (the canonical-order
// emitter) only runs on edited/rebuilt runs. The expectation was wrong.
